```typescript
function solve(s: string): string {
    let result = '';
    for (let c of s) {
        if (c >= 'a' && c <= 'z') {
            result += c;
        } else if (c === '*') {
            if (result.length > 0) {
                result = result.slice(0, -1);
            }
        } else if (c === '#') {
            result += result;
        } else if (c === '%') {
            result = result.split('').reverse().join('');
        }
    }
    return result;
}
```

